UPDATE public.garden_import_queue SET payload = '{"species": "Lemon", "species_slug": "lemon", "varieties": [{"name": "Eureka Lemon", "slug": "eureka-lemon", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "California, USA (1858), derived from Sicilian seeds, introduced to Australia 1824", "traits": "Medium-small, elliptical fruit with short neck and nipple. Bright yellow, slightly textured rind with sunken oil glands. Virtually thornless tree, 4-6m height, spreading habit.", "flesh_fruit": "Pale greenish-yellow flesh, highly acidic, very juicy. Low seed count (0-5 seeds). Classic tart lemon flavor ideal for culinary use.", "yield_notes": "Highly productive, bears fruit almost year-round in Brisbane. Main crop winter, with smaller spring/summer crops. Precocious bearer.", "growing_notes": "Best citrus for most areas of Australia. Thrives in Brisbane''s subtropical climate with year-round production. Fruit borne outside canopy, requires wind protection. Less cold tolerant than Lisbon but excellent for Brisbane conditions. Easy picking due to thornless branches.", "availability": "Widely available at Queensland nurseries including Bunnings, Daley''s Fruit Tree Nursery, and local garden centers.", "sort_order": 0}, {"name": "Taylor Eureka", "slug": "taylor-eureka", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australia - nucellar selection from Sydney, NSW (1955)", "traits": "Improved Eureka clone with enhanced vigor. Medium-sized tree, thornless, everbearing nature.", "flesh_fruit": "Similar to standard Eureka - highly acidic, juicy, low-seeded fruit. Consistent fruit quality.", "yield_notes": "More productive than standard Eureka with better crop efficiency. Year-round production.", "growing_notes": "One of the most popular commercial clones in Australia. Excellent for Brisbane''s subtropical climate. More disease resistant than older Eureka selections. Compatible with Benton citrange, Rough lemon, and sweet orange rootstocks.", "availability": "Available through specialized citrus nurseries in Queensland.", "sort_order": 1}, {"name": "Lambert Eureka", "slug": "lambert-eureka", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australia - nucellar selection from NSW (1956)", "traits": "Another improved Eureka clone, vigorous growth, spreading habit.", "flesh_fruit": "Classic Eureka characteristics - acidic, juicy, excellent flavor.", "yield_notes": "High yielding, consistent production throughout year.", "growing_notes": "Equally popular as Taylor in Australian commercial production. Well-adapted to Brisbane''s warm, humid conditions. Better management characteristics than older selections.", "availability": "Specialized Queensland citrus nurseries.", "sort_order": 2}, {"name": "Lisbon Lemon", "slug": "lisbon-lemon", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Portugal, introduced to Australia from Lisbon, multiple introductions to USA and Australia", "traits": "Large tree (up to 6m), vigorous, thorny, densely foliaged, upright growth habit. Fruit produced inside canopy providing wind/sun protection.", "flesh_fruit": "Elliptical to oblong fruit with moderate nipple. Yellow, slightly rough rind. Greenish-yellow flesh, very high juice content, very acidic. Fewer than 9 seeds.", "yield_notes": "Prolific bearer. Main crop winter/early spring in subtropical Brisbane. Most resistant to heat and adverse conditions.", "growing_notes": "Hardier than Eureka with greater cold AND heat tolerance. Excellent for Brisbane''s hot summers. Fruit quality better than Eureka due to interior canopy production protecting from wind damage. More cold tolerant but thrives equally well in subtropical heat. Thorny nature makes harvesting more difficult but provides natural pest protection.", "availability": "Widely available throughout Queensland nurseries.", "sort_order": 3}, {"name": "Prior Lisbon", "slug": "prior-lisbon", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australian selection - early-fruiting Lisbon variety", "traits": "Similar to standard Lisbon but earlier maturity. Thorny, vigorous, upright habit.", "flesh_fruit": "Identical fruit characteristics to Lisbon - highly acidic, juicy.", "yield_notes": "Fruits earlier in season than standard Lisbon, extending harvest period.", "growing_notes": "Better choice for Brisbane than standard Lisbon due to earlier cropping. Excellent heat and humidity tolerance. Preferred Melbourne alternative now used successfully in Brisbane.", "availability": "Available through specialist citrus nurseries in Queensland.", "sort_order": 4}, {"name": "Meyer Lemon (Improved)", "slug": "meyer-lemon-improved", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "China, discovered near Beijing (1908) by Frank Meyer, introduced to Narara NSW (1944). Improved virus-free clone developed later.", "traits": "Compact tree 2.5-3m, nearly thornless, round fruit (not true lemon - lemon × mandarin hybrid). Dark yellow-orange rind when ripe, thin smooth skin.", "flesh_fruit": "Deep yellow tender pulp, much lower acid than true lemons, sweeter flavor, 5-10 seeds. Juicier and less acidic than Eureka/Lisbon.", "yield_notes": "Main crop winter with some spring through summer cropping. Productive but less than Eureka.", "growing_notes": "", "availability": "", "sort_order": 5}, {"name": "Lemonade Lemon (Lemonade)", "slug": "lemonade-lemon-lemonade", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Arrived Brisbane from Pacific Islands (mid-1980s)", "traits": "Thorny tree, compact growth suitable for small spaces. Multiple fruiting periods per year.", "flesh_fruit": "Extremely mild acid profile - can be eaten like a mandarin. Sweet enough to eat fresh as a citrus fruit rather than typical sour lemon.", "yield_notes": "Fruits multiple times per year in Brisbane''s subtropical climate.", "growing_notes": "", "availability": "", "sort_order": 6}, {"name": "Villa Franca (Villafranca)", "slug": "villa-franca-villafranca", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Sicily, Italy, imported to USA (1875), introduced to Australia. Nucellar clone selected at Narara (1959).", "traits": "Belongs to Eureka group, tree closer to Lisbon in appearance but less upright and less thorny. Can grow to 8m but usually smaller.", "flesh_fruit": "Fruit similar to Eureka - few seeds, quite acidic. Smooth skin, juicy flesh.", "yield_notes": "Mainly winter cropper, but in Queensland produces significant summer crop with correct management (early harvesting, irrigation, nitrogen nutrition).", "growing_notes": "Popular in Queensland specifically for summer fruiting potential. Late season cropper complementing other varieties. Susceptible to rind breakdown in hot conditions. More commonly grown in Queensland than other Australian states due to subtropical climate encouraging summer production.", "availability": "Available at Queensland specialty citrus nurseries.", "sort_order": 7}, {"name": "Fino Lemon (Primofiori)", "slug": "fino-lemon-primofiori", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Spain (Murcia region), imported to Australia for evaluation. Also known as Mesero in Spain.", "traits": "Vigorous, somewhat thorny, tree habit similar to Eureka. Noted for smooth rind texture.", "flesh_fruit": "Nice shaped fruit, smooth textured rind. Low seed number (average 5 seeds). High quality external appearance.", "yield_notes": "Matures similar time to Eureka. Consistent heavy crops, tends to out-yield Eureka. Produces several smaller crops at Gosford NSW.", "growing_notes": "Imported with aim of producing high quality fruit suitable for export September-November. Quick to mature. Elite budwood becoming more available for Brisbane home gardeners. Performs well in Australian subtropical trials.", "availability": "Limited but increasing availability through specialist Queensland nurseries.", "sort_order": 8}, {"name": "Verna Lemon", "slug": "verna-lemon", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Spain, imported from Morocco to Australia", "traits": "Large spreading productive tree, thornless. Late season cropper.", "flesh_fruit": "Virtually seedless. Tender pulp, good acid content. Less juice than Eureka but excellent quality. Medium-thick rind main crop, thinner in subsequent crops.", "yield_notes": "Main crop late winter/spring in Southern Australia. Multiple crops throughout year in coastal NSW. Second crop (''Secundus'') of inferior quality.", "growing_notes": "", "availability": "", "sort_order": 9}, {"name": "Yen Ben Lemon", "slug": "yen-ben-lemon", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "New Zealand, planted Burrum Heads Queensland (late 1930s), commercially grown New Zealand since 1991", "traits": "Bush-like appearance when laden with fruit. Darker, thicker leaves than typical lemon. Precocious bearer.", "flesh_fruit": "Smaller fruit than Eureka (120-130g). Smooth textured thin rind. High quality external appearance and juice content. Juice maintained with proper long-term storage.", "yield_notes": "Good production levels. Main winter crop with smaller intermediate crops.", "growing_notes": "Minor commercial plantings in Australia. Under evaluation in variety trials. High juice content and smooth rind appealing characteristics. Originally planted in Queensland indicating regional suitability.", "availability": "Limited availability, specialty citrus nurseries in Queensland.", "sort_order": 10}, {"name": "Bush Lemon (Rough Lemon)", "slug": "bush-lemon-rough-lemon", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "origin": "Naturalized in subtropical Australia, grows wild in Queensland bushland", "traits": "Good sized tree, small thorns. Bumpy, thick-skinned fruit ranging yellow to orange coloring. Wild, rugged appearance. Very hardy.", "flesh_fruit": "Thick skin with true lemon flavor. Low juice content but iconic citrus taste. Seeds present, mildly sour flavor. Good for zest.", "yield_notes": "Moderate production, frost-free zones only.", "growing_notes": "Preferred lemon for Australian lemon butter/curd. Easy to grow, naturally adapted to Brisbane''s subtropical conditions. Wild form demonstrates excellent humidity and heat tolerance. Leaves make delicious tea. Often used as rootstock for grafting due to vigor and disease resistance.", "availability": "Grows wild, can be sourced from specialized native/heritage plant nurseries in Queensland or propagated from wild specimens.", "sort_order": 11}, {"name": "Ponderosa Lemon", "slug": "ponderosa-lemon", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "USA, chance seedling discovered 1880s, launched commercially 1900. Hybrid of citron × pomelo (not true lemon).", "traits": "Dwarf to medium tree (2-4m suitable for Brisbane gardens), thorny, purple-tinged flowers and new growth. Suitable for pots.", "flesh_fruit": "Massive grapefruit-sized fruit (2-4 pounds), thick bumpy rind. Extremely acidic juice similar to true lemon. Many seeds. Pale yellow-green flesh.", "yield_notes": "Year-round flowering and fruiting. High productivity of enormous fruits.", "growing_notes": "Ornamental value with impressive fruits that can remain on tree for months. Less cold-hardy than true lemons but excellent for Brisbane''s warm climate. Mainly grown as ornamental in California/Florida. Fruit can substitute measure-for-measure for regular lemons. Enough juice in one fruit for several lemon pies. Ideal for Brisbane container growing.", "availability": "Available at Queensland specialty nurseries and online suppliers.", "sort_order": 12}, {"name": "Bearss Lemon", "slug": "bearss-lemon", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Florida USA, selected 1952 from seedling planted 1892 in Bearrs Grove, Lutz. Originally called ''Sicily''.", "traits": "Vigorous, thornless to nearly thornless tree. Fast grower, tends to produce water sprouts.", "flesh_fruit": "Very juicy, high-acid fruit. High levels of lemon oil in rind. Fewer seeds, tarter and more sour than other varieties. High-grade juice.", "yield_notes": "Abundant fruit production July through December. More productive than many citrus varieties.", "growing_notes": "Excellent for juicing and baking due to high oil content. Strong growth rate and near-thornless nature makes maintenance easier. Good adaptation to subtropical conditions. Available on dwarf rootstocks suitable for Brisbane gardens.", "availability": "Available through Queensland citrus specialty suppliers.", "sort_order": 13}, {"name": "Genoa Lemon (Genova)", "slug": "genoa-lemon-genova", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Italian origin, like Villafranca. Recently becoming available in Australia.", "traits": "Smaller tree habit than Eureka/Lisbon. Fewer and smaller thorns on fruiting branches.", "flesh_fruit": "Classic lemon characteristics, high quality fruit.", "yield_notes": "Good production levels for smaller tree size.", "growing_notes": "", "availability": "", "sort_order": 14}, {"name": "Kagzi Nimbu (Kargzi Lime) 🌏", "slug": "kagzi-nimbu-kargzi-lime", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "", "sort_order": 0}, {"name": "Vikram (Acid Lime)", "slug": "vikram-acid-lime", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Recently identified high-yielding cultivar for India", "traits": "Improved variety selected for high productivity. Medium tree size.", "flesh_fruit": "High juice content, good acidity, typical lime characteristics.", "yield_notes": "High yielding cultivar specifically developed for commercial production.", "growing_notes": "Gaining popularity as improved alternative to Kagzi. Well-suited for Kerala''s tropical monsoon conditions. Disease resistant characteristics.", "availability": "Available through Kerala agricultural universities and government nurseries.", "sort_order": 1}, {"name": "Prumalini (Acid Lime)", "slug": "prumalini-acid-lime", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Recently identified high-yielding cultivar for India", "traits": "Improved variety with enhanced productivity characteristics.", "flesh_fruit": "Juicy, acidic fruit typical of quality acid limes.", "yield_notes": "High yielding selection for commercial cultivation.", "growing_notes": "Modern improved cultivar gaining popularity in Kerala. Adapted to monsoon climate conditions.", "availability": "Kerala agricultural department nurseries and certified suppliers.", "sort_order": 2}, {"name": "PKM (Acid Lime)", "slug": "pkm-acid-lime", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Recently identified high-yielding cultivar for India", "traits": "Improved acid lime variety with commercial potential.", "flesh_fruit": "Quality juice, good acid content for commercial use.", "yield_notes": "High-yielding selection for improved productivity.", "growing_notes": "Part of recent breeding programs for improved Indian citrus. Suitable for Kerala''s humid tropical climate.", "availability": "Government agricultural nurseries in Kerala.", "sort_order": 3}, {"name": "Sai Sharbati (Acid Lime)", "slug": "sai-sharbati-acid-lime", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Recently identified high-yielding cultivar for India", "traits": "Modern improved acid lime variety.", "flesh_fruit": "High quality juice characteristics, commercial grade.", "yield_notes": "High-yielding commercial variety.", "growing_notes": "Part of improved cultivar program gaining popularity. Well-adapted to tropical monsoon conditions of Kerala.", "availability": "Kerala state agricultural nurseries and certified suppliers.", "sort_order": 4}, {"name": "Gol Nemu (Assam Lemon) 🌏", "slug": "gol-nemu-assam-lemon", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Assam, India - indigenous to northeastern India (Nemu Tenga variety)", "traits": "Round shape, larger than other Indian varieties. Oblong shape with thick bumpy rind. Warty, rough texture.", "flesh_fruit": "Sweet flavor, modest size. Green to deep yellow when ripe. Highly concentrated acidic juice. Less seeds than other varieties.", "yield_notes": "Good productivity in tropical regions.", "growing_notes": "Hardy nature thrives in tropical climates like Kerala. Distinctive from smooth-skinned market lemons. Used extensively in Assamese and South Indian cuisine. Powerful flavor enhancer. High aromatic citrus oils. Adapts well to Kerala''s monsoon conditions.", "availability": "Available through specialty nurseries in Kerala, South Indian agricultural suppliers.", "sort_order": 5}, {"name": "Kazi Nemu (Assam Lemon) 🌏", "slug": "kazi-nemu-assam-lemon", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Assam, India - indigenous variety (Nemu Tenga type)", "traits": "Elongated oval shape, different from round Gol Nemu. Medium tree size adapted to tropical conditions.", "flesh_fruit": "Much juicier than other lemon varieties. Highly acidic, powerful citrus flavor. Exceptionally juicy compared to Gol Nemu.", "yield_notes": "Productive in tropical climates, good juice yield.", "growing_notes": "Widely used for therapeutic benefits and medicinal properties. Primarily used in commercial and culinary activities across India. Popular in Assamese cuisine. High juice content makes it preferred choice for cooking and beverages. Excellent adaptation to Kerala''s high humidity and monsoon rains.", "availability": "Kerala specialty nurseries, South Indian suppliers, some availability in local markets.", "sort_order": 6}, {"name": "Gandharaj Lemon 🌏", "slug": "gandharaj-lemon", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Bengal, India - fragrant indigenous variety native to India", "traits": "Hard green skin distinguishing it from common lemons. Powerful, distinctive aroma - most fragrant Indian lemon variety.", "flesh_fruit": "Intensely aromatic and flavorful - thin slice revives any dish. High vitamin C and citrus content. Powerful flavor despite small size.", "yield_notes": "Moderate production, valued for quality over quantity.", "growing_notes": "", "availability": "", "sort_order": 7}, {"name": "Pat Nebu (Assam Lemon) 🌏", "slug": "pat-nebu-assam-lemon", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Assam, India, also grown in Nepal regions", "traits": "Bright appearance, small size, smooth and glossy skin texture.", "flesh_fruit": "Balanced acidic composition - not too sour, not too mild. Relatively fewer seeds. Delicious scent. Medium-sized with pleasant aroma.", "yield_notes": "Moderate production suitable for home gardens and local markets.", "growing_notes": "Balanced flavor profile makes it versatile for various uses. Smooth texture preferred by many consumers. Grows well in Kerala''s tropical climate similar to its Assam origins.", "availability": "Kerala specialty suppliers, northeastern India plant sources.", "sort_order": 8}, {"name": "Rough Lemon (Indian) 🌏", "slug": "rough-lemon-indian", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Wilds of Northern India, commercial cultivation throughout India", "traits": "Good sized trees with small thorns. Rough, rugged, irregular skin shape. No defined shape, harsh exterior. Strong scent and flavor.", "flesh_fruit": "Very less juice and pulp. Mildly sour flavor. Oval or oblong yellow fruit. Loads of seeds.", "yield_notes": "Moderate fruit production, valued more as rootstock.", "growing_notes": "", "availability": "", "sort_order": 9}, {"name": "Nepali Round", "slug": "nepali-round", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Despite name, successfully grown in South India for years, origins in India", "traits": "Round shape as name indicates. Bright yellow color when ripe.", "flesh_fruit": "Very juicy, very few seeds inside - one of the juiciest Indian varieties. Good balance of acidity.", "yield_notes": "Good productivity, reliable bearer.", "growing_notes": "Successful cultivar in South India including Kerala despite Nepali name. Low seed count major advantage for juice production. Well-adapted to Kerala''s tropical monsoon climate. Popular in southern states commercial production.", "availability": "Available throughout South India including Kerala nurseries and agricultural centers.", "sort_order": 10}, {"name": "Nepali Oblong", "slug": "nepali-oblong", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Indigenous to India (despite name), traditional variety", "traits": "Oblong/elongated shape distinguishing from Nepali Round. Medium tree size.", "flesh_fruit": "Good juice content, acidic flavor typical of quality lemons.", "yield_notes": "Moderate to good production levels.", "growing_notes": "", "availability": "", "sort_order": 11}, {"name": "Lisbon Lemon (India)", "slug": "lisbon-lemon-india", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Portugal, adapted for Indian tropical conditions", "traits": "Greenish-yellow color, short-living variety. Average size, prominent nipple at apex. More acidic nature. Similar to Eureka in elongated shape.", "flesh_fruit": "Quite acidic, typical lemon flavor. Good juice content.", "yield_notes": "Low yielding cultivar but valued for quality.", "growing_notes": "", "availability": "", "sort_order": 12}, {"name": "Meyer Lemon (India)", "slug": "meyer-lemon-india", "lineage_type": "hybrid", "climate_slug": "tropical-monsoon", "origin": "China, adapted for Indian conditions, available at Kerala nurseries", "traits": "Bright yellow color, noticeable nipple at top. Compact growth suitable for Kerala home gardens.", "flesh_fruit": "Sweet and tangy flavor - sweeter than traditional lemons. Less acidic, more juice content. Thin skin.", "yield_notes": "Short-living, low yielding cultivar but popular for quality.", "growing_notes": "", "availability": "", "sort_order": 13}, {"name": "Eureka Lemon (India)", "slug": "eureka-lemon-india", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "California/Sicily, adapted and grown commercially in India", "traits": "Similar characteristics to international Eureka. Medium tree suitable for Kerala conditions.", "flesh_fruit": "Classic acidic lemon flavor, juicy, low seed count.", "yield_notes": "Productive throughout year in Kerala''s climate.", "growing_notes": "", "availability": "", "sort_order": 14}, {"name": "Ponderosa Lemon (India)", "slug": "ponderosa-lemon-india", "lineage_type": "hybrid", "climate_slug": "tropical-monsoon", "origin": "USA hybrid, now available in India including Kerala", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "", "sort_order": 15}, {"name": "Italian Lemon", "slug": "italian-lemon", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Italy, adapted for Indian cultivation", "traits": "Classic Italian lemon characteristics adapted to Indian conditions.", "flesh_fruit": "Quality fruit with good juice content and acidity.", "yield_notes": "Moderate production suitable for home gardens.", "growing_notes": "", "availability": "", "sort_order": 16}, {"name": "Malta Lemon", "slug": "malta-lemon", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Mediterranean region, varieties popular in South India", "traits": "Adapted Malta variety suitable for South Indian conditions.", "flesh_fruit": "Good quality lemon characteristics.", "yield_notes": "Moderate production levels.", "growing_notes": "", "availability": "", "sort_order": 17}, {"name": "Pant Lemon", "slug": "pant-lemon", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "India - developed variety for Indian conditions", "traits": "Indian-developed variety suited to local conditions.", "flesh_fruit": "Good juice and acid content for commercial use.", "yield_notes": "Developed for improved productivity.", "growing_notes": "", "availability": "", "sort_order": 18}, {"name": "Rangpur Lemon 🌏", "slug": "rangpur-lemon", "lineage_type": "hybrid", "climate_slug": "tropical-monsoon", "origin": "Originally cultivated India and Southeast Asia, naturalized in tropical regions", "traits": "Not true lemon - hybrid of mandarin orange × lime. Striking orange-colored rind resembling small tangerine. Small tree suitable for Kerala gardens.", "flesh_fruit": "Highly tangy, sharp acidic flavor with slightly spicy notes. More complex flavor than regular lemons. Orange rind with tart juice.", "yield_notes": "Good productivity in tropical conditions.", "growing_notes": "Indigenous to India originally. Often used in curries, chutneys, desserts (custards, ice cream). Zest has intense citrus aroma used in baking and spice blends. Common in Indian, Thai, Indonesian cuisine. Vibrant acidity enhances flavor profiles. Perfectly suited to Kerala''s tropical monsoon climate.", "availability": "Available in Kerala through specialty nurseries, traditional plant suppliers.", "sort_order": 19}, {"name": "Sweet Lime (Mausambi) 🌏", "slug": "sweet-lime-mausambi", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Native to Malabar and Nilgiri regions of South India including Kerala", "traits": "Grows mainly in Malabar and Nilgiris regions. Non-acidic nature unusual for citrus. Larger fruit, juicier than typical lemons.", "flesh_fruit": "Sweet and low-acidic - can be eaten as fruit rather than juicing. Mild, pleasant flavor. Larger and juicier than acidic varieties.", "yield_notes": "Good productivity in native Kerala regions.", "growing_notes": "", "availability": "", "sort_order": 20}, {"name": "Lucknow Seedless", "slug": "lucknow-seedless", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Lucknow, Uttar Pradesh, India - developed Indian variety", "traits": "Medium size fruit with yellow color. Seedless characteristic highly valued.", "flesh_fruit": "Seedless fruit ideal for juice production. Good juice content and acidity.", "yield_notes": "Moderate production, valued for seedless trait.", "growing_notes": "", "availability": "", "sort_order": 21}], "variety_count": 37}'::jsonb,
