UPDATE public.garden_import_queue SET payload = '{"species": "Lychee", "species_slug": "lychee", "varieties": [{"name": "Kwai Mai Pink", "slug": "kwai-mai-pink", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "China (Guangdong province), ancient cultivar with 500-600 year history. Introduced to Australia in 1930s.", "traits": "Round fruit, red skin with slight orange hue. Medium size, small to medium seed. Distinctive dark green/black tubercle tips near fruit stalk.", "flesh_fruit": "Spicy-sweet flavor, firm flesh, excellent quality. Small seed with high flesh recovery.", "yield_notes": "High productivity, reliable annual bearer.", "growing_notes": "", "availability": "", "sort_order": 0}, {"name": "Wai Chee", "slug": "wai-chee", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "China (Guangdong province), 500-600 year heritage. Means ''cherished lychee''.", "traits": "Heart-shaped to round fruit. Deep red skin with thick, irregular segments and smooth protuberances. Small, oval leaflets that curve upwards.", "flesh_fruit": "Very sweet and juicy, watery texture when fully ripe. Medium sized fruit, flat shoulders.", "yield_notes": "Very consistent bearer, reliable annual crops with good alternating year yields.", "growing_notes": "", "availability": "Available at Queensland nurseries including Daley''s Fruit Tree Nursery.", "sort_order": 1}, {"name": "Tai So", "slug": "tai-so", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "China, ancient cultivar. First introduced to Hawaii in 1873, to Australia in 1930s.", "traits": "Egg-shaped fruit, distinctive spearhead/chicken-heart shape. Red skin with hairlike sharp protuberances. Large, glossy dark green leaves with upward curl.", "flesh_fruit": "Sweet and aromatic with pleasant flavor. Variable chicken-tongue seed percentage depending on season.", "yield_notes": "Irregular bearing, good crops every 2-3 years. Can produce 10-50kg per 10-year-old tree.", "growing_notes": "", "availability": "", "sort_order": 2}, {"name": "Bengal", "slug": "bengal", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "India (historical variety from Bengal region), introduced to Australia in late 1800s.", "traits": "Bright red skin, round to heart-shaped fruit. Large leaflets, mid-green with distinctive twist along length. Sharp-pointed protuberances. Uneven shoulders. Large, bold pointed seed.", "flesh_fruit": "Very sweet with exceptional rose-like fragrance. Classic lychee flavor profile.", "yield_notes": "Irregular growing habit affects production. Rarely produces chicken-tongue seeds.", "growing_notes": "", "availability": "", "sort_order": 3}, {"name": "Salathiel", "slug": "salathiel", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australia (developed in Australia, surname of developer), introduced within last 50 years.", "traits": "Bright red with smooth skin, slightly lopsided round shape. Small fruit (approximately 30-32mm diameter). Weak vigor, compact tree.", "flesh_fruit": "Very high proportion of small/aborted seeds (near-seedless). Excellent flesh-to-seed ratio. Sweet flavor, good quality.", "yield_notes": "Moderate production.", "growing_notes": "", "availability": "Available at Queensland nurseries including Daley''s Fruit Tree Nursery.", "sort_order": 4}, {"name": "Souey Tung", "slug": "souey-tung", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "China (Fujian province), relatively young cultivar (approximately 100 years old). First variety cultivated in Australia.", "traits": "Large fruit, red to orange-red skin. Thin skin with obvious suture line. Uneven shoulders. Dominates Fujian province plantings.", "flesh_fruit": "Good flavor and quality. Produces some chicken-tongue seeds.", "yield_notes": "Good productivity.", "growing_notes": "", "availability": "", "sort_order": 5}, {"name": "Baitaying (Baitangying)", "slug": "