UPDATE public.garden_import_queue SET payload = '{"species": "Macadamia", "species_slug": "macadamia", "varieties": [{"name": "H2 (Hinde) 🏆", "slug": "h2-hinde", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Colliston, Gold Coast hinterland, Queensland, c.1920s. Parent tree still survives. Named after Hinde family property.", "traits": "Medium-large tree, vigorous growth. Dense canopy. Cream-white flowers. Smooth-margined leaves in whorls of 3.", "flesh_fruit": "", "yield_notes": "Good consistent yields. Reliable producer.", "growing_notes": "", "availability": "Widely available as rootstock from Queensland nurseries. 90% of Australian grafted trees use H2 rootstock. Historical significance as one of only two Australian varieties endorsed 1960s-1980s.", "sort_order": 0}, {"name": "Walter Hill Tree (Brisbane Botanic Gardens) 🏆", "slug": "walter-hill-tree-brisbane-botanic-gardens", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Brisbane Botanic Gardens, City, 1858. World''s first cultivated macadamia tree. Seeds from Gympie. Planted by Walter Hill (superintendent). Still producing nuts.", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Unique heritage specimen. Not commercially propagated but accessible for viewing Brisbane Botanic Gardens rainforest section.", "sort_order": 1}, {"name": "344 (Kau/HAES 344)", "slug": "344-kau-haes-344", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Hawaii, early 20th century (1920s). Hawaiian Agricultural Experiment Station selection. From Queensland genetic base.", "traits": "Upright tree with dense canopy. Better wind resistance than other varieties. Adaptable to wide range of climates. Yellow-hued blossoms September flowering.", "flesh_fruit": "", "yield_notes": "Early season cropping. Reliable yields. 3.2-3.9 fruits per raceme.", "growing_notes": "", "availability": "", "sort_order": 2}, {"name": "246 (Keauhou/HAES 246)", "slug": "246-keauhou-haes-246", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Hawaii, 1940s-1950s. Hawaiian Agricultural Experiment Station. Also known as Keauhou. Standard commercial variety.", "traits": "Medium to large tree, spreading growth habit. Dense canopy. Large impressive inflorescences.", "flesh_fruit": "", "yield_notes": "Significantly higher in mixed plantings (16kg more per tree). Benefits from cross-pollination. Medium to large spreading tree.", "growing_notes": "", "availability": "", "sort_order": 3}, {"name": "A4", "slug": "a4", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Australia, Hidden Valley selection. Modern commercial hybrid.", "traits": "Medium-sized tree with open canopy. Vigorous and precocious. Moderate growth. Early bearing year 4-5. Open canopy but brittle viny branches prone to wind damage.", "flesh_fruit": "", "yield_notes": "Moderate at 3-4 t/ha. Alternate bearing tendency. Precocious - early commercial yields year 3. Well suited to high density planting.", "growing_notes": "", "availability": "Widely available Queensland nurseries. Popular commercial variety. Premium price $40-60 per tree. Daley''s, Southern Cross, regional suppliers.", "sort_order": 4}, {"name": "A16", "slug": "a16", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Australia. Modern commercial hybrid selection.", "traits": "Upright growth but brittle branches. Aggressive regrowth post-pruning. Yellow-hued flowers extending into October.", "flesh_fruit": "", "yield_notes": "Early bearing year 4-5, after Beaumont and A4. Higher yields than A4, up to 3 t/ha. Mid-season harvest.", "growing_notes": "", "availability": "Queensland nurseries. Industry standard variety. Used in regional variety trials throughout Queensland.", "sort_order": 5}, {"name": "A38", "slug": "a38", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Australia. Modern selection.", "traits": "Medium-sized tree. Good structure.", "flesh_fruit": "", "yield_notes": "Reliable yields.", "growing_notes": "", "availability": "", "sort_order": 6}, {"name": "A203", "slug": "a203", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Australia. CitroGold selection. Protected variety.", "traits": "Modern commercial variety. Good tree structure.", "flesh_fruit": "", "yield_notes": "Good yields. Modern high-performance cultivar.", "growing_notes": "", "availability": "Licensed nurseries only. RedSun Hortitech accredited to propagate. South African and Australian commercial plantings.", "sort_order": 7}, {"name": "A268", "slug": "a268", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Australia. CitroGold selection. Protected variety.", "traits": "Medium tree size. Good canopy structure.", "flesh_fruit": "", "yield_notes": "Excellent yields. Industry standard comparison variety.", "growing_notes": "", "availability": "", "sort_order": 8}, {"name": "741 (HAES 741)", "slug": "741-haes-741", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Hawaii Agricultural Experiment Station. Reference genome cultivar.", "traits": "Grows very tall. Needs regular topping. Dense canopy requires internal branch removal. Upright vigorous growth.", "flesh_fruit": "", "yield_notes": "Good reliable yields. Benchmark variety in trials. 3.2-3.9 fruits per raceme.", "growing_notes": "", "availability": "Queensland nurseries. Widely planted commercial variety. Standard grafting scion. Used extensively in breeding programs.", "sort_order": 9}, {"name": "788 (HAES 788)", "slug": "788-haes-788", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Hawaii Agricultural Experiment Station.", "traits": "Medium tree. Longest inflorescences (15.7cm). Most flowers per inflorescence.", "flesh_fruit": "", "yield_notes": "Good producer. Impressive flowering display.", "growing_notes": "", "availability": "Australian and international nurseries. Commercial variety. Hillgro Nursery SA produces grafted trees.", "sort_order": 10}, {"name": "814", "slug": "814", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australia/Hawaii. Modern commercial selection.", "traits": "Cutting rootstock produces smaller trees than seedling. Good for high-density plantings. Compact growth.", "flesh_fruit": "", "yield_notes": "Precocious - early bearing. High subsequent yields. Good productivity.", "growing_notes": "", "availability": "Queensland and international nurseries. Widely planted South Africa. Hillgro, Amorentia, RedSun propagate. Available as rooted cuttings or grafted.", "sort_order": 11}, {"name": "816 (HAES 816)", "slug": "816-haes-816", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Hawaii Agricultural Experiment Station. Industry standard.", "traits": "Medium tree size. Cutting rootstock produces smaller trees. Stick-tight variety - nuts don''t drop readily, requires ethephon applications.", "flesh_fruit": "", "yield_notes": "Good commercial yields. Industry standard benchmark. Mid-late season.", "growing_notes": "", "availability": "Widely available Queensland nurseries. Major commercial variety Australia and South Africa. Daley''s, RedSun, Amorentia, international suppliers. Available grafted or rooted cuttings.", "sort_order": 12}, {"name": "842 (HAES 842)", "slug": "842-haes-842", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Hawaii Agricultural Experiment Station/Australia selection.", "traits": "Good tree structure. Moderate growth.", "flesh_fruit": "", "yield_notes": "Precocious - favored for early bearing. High subsequent yields. Good productivity.", "growing_notes": "", "availability": "Queensland and South African nurseries. Commercial variety. Hillgro, Amorentia propagate. Available grafted trees.", "sort_order": 13}, {"name": "849 (HAES 849)", "slug": "849-haes-849", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Hawaii Agricultural Experiment Station/CSIRO selection.", "traits": "Beautiful spreading tree with dense canopy. Moderate size suitable for gardens. Creamy white blossoms.", "flesh_fruit": "", "yield_notes": "Mid to late season cropping. Good yields. Own-rooted trees performed well in trials. Time to fruit 2-3 years grafted.", "growing_notes": "", "availability": "Queensland nurseries. Daley''s Fruit Tree Nursery, Ross Creek Tropicals. Ships QLD, NSW, VIC, SA, ACT. Grafted trees 6L bags. Relatively new so increasing availability.", "sort_order": 14}, {"name": "863 (HAES 863)", "slug": "863-haes-863", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "CSIRO breeding program. New variety 2017 release.", "traits": "New high-performing cultivar. Good tree structure. Specifically selected for Australian conditions.", "flesh_fruit": "", "yield_notes": "Up to 38% productivity boost over 741. Cumulative 9-year yields superior. High-yielding modern variety. Evaluated against industry standards 344, 268, 741, 816, A16.", "growing_notes": "", "availability": "South African nurseries - Hillgro. Increasing Australian availability. Released 2017 so expanding production. Contact QAAFI/CSIRO licensees.", "sort_order": 15}, {"name": "Beaumont (695)", "slug": "beaumont-695", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Discovered by Dr. J.H. Beaumont, University of Hawaii. Most widely planted cultivar South Africa. Industry standard.", "traits": "Upright growth habit, space-efficient. Bright pink flowers on long racemes. Vibrant reddish new leaves. Dense canopy. Impressive grape-like nut clusters can break branchlets. Nuts don''t drop when ripe - stick-tight.", "flesh_fruit": "", "yield_notes": "Quickest to bearing - useful crop by year 4, improving thereafter. Crops prodigiously when well-pollinated. 18kg per tree by year 8. High yield potential. Alternate bearing in some locations. Late season harvest.", "growing_notes": "", "availability": "Widely available Queensland nurseries. Daley''s, Southern Cross, regional suppliers. Most popular home garden variety. Common rootstock - H2 and 695 are industry standard rootstocks globally. Price $30-50 per tree. Available both grafted trees and rooted clonal cuttings.", "sort_order": 16}, {"name": "Daddow", "slug": "daddow", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australia, Queensland. Named selection.", "traits": "Vigorous dense spreading tree. Smooth-leaved. Good canopy density.", "flesh_fruit": "", "yield_notes": "Best all-round performer over six different trial sites throughout QLD and NSW. Consistent reliable production. Proven across diverse conditions.", "growing_notes": "", "availability": "", "sort_order": 17}, {"name": "Own Choice", "slug": "own-choice", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australia. Commercial selection.", "traits": "Good tree structure. Standard growth pattern.", "flesh_fruit": "", "yield_notes": "Good pollinator for Beaumont. Crops moderately well. May be self-fertile. Nuts must be picked when ripe (don''t drop).", "growing_notes": "", "availability": "", "sort_order": 18}, {"name": "Own Venture", "slug": "own-venture", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australia. Commercial selection.", "traits": "Good commercial growth characteristics.", "flesh_fruit": "", "yield_notes": "Reliable commercial yields.", "growing_notes": "", "availability": "", "sort_order": 19}, {"name": "MiniMaca (Dwarf Macadamia)", "slug": "minimaca-dwarf-macadamia", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Northern NSW discovery. Rare unique miniature selection. Plant Breeders Rights protected.", "traits": "Unique miniature features. Grows to half normal size. Stunning pink new growth. Columnar growth habit. Can be maintained as hedge with regular pruning. Semi-dwarfing, compact tree. Slow growing. Wind tolerant.", "flesh_fruit": "", "yield_notes": "High yielder for its size. Excellent nut quality. Precocious bearer.", "growing_notes": "", "availability": "Daley''s Fruit Tree Nursery. Rare collector''s variety. Plant Breeders Rights - propagation prohibited. Premium specialty selection. Ideal for Australian bushfood collectors.", "sort_order": 20}, {"name": "Pink Flowering (Ornamental)", "slug": "pink-flowering-ornamental", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Australia. Hybrid selection. Trademarked variety.", "traits": "Stunning pink racemes of flowers in Spring. Attractive pink flowers and maroon new growth. Popular for ornamental colorful features. Propagation prohibited (trademarked).", "flesh_fruit": "", "yield_notes": "Produces well after 4th year. Nuts fall when ripe from Autumn through Winter.", "growing_notes": "", "availability": "Daley''s Fruit Tree Nursery and specialty nurseries. Trademarked variety. Ornamental macadamia selection. Warm temperate to subtropical zones.", "sort_order": 21}, {"name": "344 (Kau/HAES 344)", "slug": "344-kau-haes-344", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Hawaii, early 20th century. Hawaiian Agricultural Experiment Station selection.", "traits": "Upright tree with dense canopy. Better wind resistance. Wide climate adaptability including tropical conditions.", "flesh_fruit": "", "yield_notes": "Early season cropping. Reliable yields. Good production.", "growing_notes": "", "availability": "", "sort_order": 0}, {"name": "246 (Keauhou/HAES 246)", "slug": "246-keauhou-haes-246", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Hawaii, 1940s-1950s. Hawaiian Agricultural Experiment Station.", "traits": "Medium to large spreading tree. Dense canopy. Good foliage coverage.", "flesh_fruit": "", "yield_notes": "Higher yields in mixed plantings. Benefits greatly from cross-pollination. Good production.", "growing_notes": "", "availability": "", "sort_order": 1}, {"name": "741 (HAES 741)", "slug": "741-haes-741", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Hawaii Agricultural Experiment Station. Reference genome cultivar.", "traits": "Vigorous upright growth. Grows tall. Dense canopy.", "flesh_fruit": "", "yield_notes": "Good reliable yields. Benchmark variety for comparisons.", "growing_notes": "", "availability": "", "sort_order": 2}, {"name": "788 (HAES 788)", "slug": "788-haes-788", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Hawaii Agricultural Experiment Station.", "traits": "Medium tree. Impressive long inflorescences. Abundant flowering.", "flesh_fruit": "", "yield_notes": "Good producer. Heavy flowering indicates good yield potential.", "growing_notes": "", "availability": "", "sort_order": 3}, {"name": "800 (HAES 800)", "slug": "800-haes-800", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Hawaii Agricultural Experiment Station.", "traits": "Shorter inflorescences (10.7cm). Fewer flowers per inflorescence (89).", "flesh_fruit": "", "yield_notes": "Lower fruit set (1.2 fruits per raceme). Fewer nuts but large size.", "growing_notes": "", "availability": "Specialized international variety. May be available through agricultural research contacts in India.", "sort_order": 4}, {"name": "Beaumont (695)", "slug": "beaumont-695", "lineage_type": "hybrid", "climate_slug": "tropical-monsoon", "origin": "Discovered Dr. J.H. Beaumont, University of Hawaii. Widely planted globally.", "traits": "Upright space-efficient growth. Pink flowers, reddish new leaves. Quick to bearing. Nuts don''t drop (stick-tight).", "flesh_fruit": "", "yield_notes": "Quickest bearing (year 4). Prodigious yields when pollinated. 18kg by year 8. High yield potential. Drought tolerant.", "growing_notes": "", "availability": "", "sort_order": 5}, {"name": "A4", "slug": "a4", "lineage_type": "hybrid", "climate_slug": "tropical-monsoon", "origin": "Australia, Hidden Valley selection.", "traits": "Open canopy, vigorous precocious growth. Brittle branches.", "flesh_fruit": "", "yield_notes": "Precocious - early commercial yields year 3. Moderate 3-4 t/ha. High density suitable.", "growing_notes": "", "availability": "", "sort_order": 6}, {"name": "A16", "slug": "a16", "lineage_type": "hybrid", "climate_slug": "tropical-monsoon", "origin": "Australia. Modern hybrid selection.", "traits": "Upright growth, brittle branches. Aggressive regrowth.", "flesh_fruit": "", "yield_notes": "Higher than A4, up to 3 t/ha. Early bearing year 4-5. Mid-season.", "growing_notes": "", "availability": "", "sort_order": 7}, {"name": "814", "slug": "814", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Australia/Hawaii selection.", "traits": "Smaller tree size, compact. Good for high-density planting.", "flesh_fruit": "", "yield_notes": "Precocious early bearing. High subsequent yields.", "growing_notes": "", "availability": "", "sort_order": 8}, {"name": "816 (HAES 816)", "slug": "816-haes-816", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Hawaii Agricultural Experiment Station.", "traits": "Medium tree. Compact when on cutting rootstock. Stick-tight (nuts don''t drop).", "flesh_fruit": "", "yield_notes": "Good commercial yields. Industry benchmark. Mid-late season.", "growing_notes": "", "availability": "", "sort_order": 9}, {"name": "842 (HAES 842)", "slug": "842-haes-842", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Hawaii Agricultural Experiment Station/Australia.", "traits": "Good tree structure. Moderate growth.", "flesh_fruit": "", "yield_notes": "Precocious bearing. High subsequent yields.", "growing_notes": "", "availability": "", "sort_order": 10}, {"name": "Kakea (508/HAES 508)", "slug": "kakea-508-haes-508", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Hawaii. Hawaiian Agricultural Experiment Station.", "traits": "Good tree structure. Proven Hawaiian cultivar.", "flesh_fruit": "", "yield_notes": "Higher yield than 246 (Keauhou). Good commercial production.", "growing_notes": "", "availability": "Hawaiian variety available through international suppliers. May be sourced through agricultural research contacts India. Tested Bangalore conditions successfully.", "sort_order": 11}, {"name": "Keaau (660/HAES 660)", "slug": "keaau-660-haes-660", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Hawaii. Named after Keaau region Hawaii.", "traits": "Upright growth pattern. Favored over spreading types. Good structure.", "flesh_fruit": "", "yield_notes": "High yielding. Good commercial production.", "growing_notes": "", "availability": "Hawaiian variety. May be available through specialized Indian importers or agricultural research institutions. Tested in Indian conditions.", "sort_order": 12}, {"name": "Nelmak 2 (Nelspruit Macadamia 2)", "slug": "nelmak-2-nelspruit-macadamia-2", "lineage_type": "hybrid", "climate_slug": "tropical-monsoon", "origin": "South Africa, Nelspruit ARC 1973. Nelspruit Agricultural Research Council selection. Named Nelspruit Makadamia in Afrikaans.", "traits": "Vigorous prolific grower. Fragrant pink flowers. Nuts hang in clusters. Beautiful ornamental.", "flesh_fruit": "", "yield_notes": "Starts bearing year 3 (very precocious). Healthy nut production. Good yields. Mid-season harvest.", "growing_notes": "", "availability": "", "sort_order": 13}, {"name": "Macadamia integrifolia Seedling 🌱", "slug": "macadamia-integrifolia-seedling", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "🌏 INDIGENOUS - Native Queensland/NSW Australia. Wild genetic diversity.", "traits": "Evergreen tree 10-20m tall. Smooth-margined mature leaves (juvenile leaves serrated). Whorls of 3 leaves. Cream-white flowers. Green new growth. Smooth spherical shells.", "flesh_fruit": "", "yield_notes": "Variable. Takes 10-12 years seed to production (vs 4-6 years grafted). Some produce well, others minimal. Unpredictable.", "growing_notes": "", "availability": "", "sort_order": 14}, {"name": "Macadamia tetraphylla Seedling 🌱", "slug": "macadamia-tetraphylla-seedling", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "🌏 INDIGENOUS - Native Gold Coast to Northern NSW Australia. Bush Nut. Wild genetic diversity.", "traits": "Evergreen tree up to 20m. Four spiny serrated leaves per whorl (vs 3 for integrifolia). Pink flowers. Pink/maroon new growth. Rough pebbled shells. Better cold tolerance than integrifolia.", "flesh_fruit": "", "yield_notes": "Variable. 10-12 years seed to production. Some productive, others minimal. Unpredictable yields.", "growing_notes": "", "availability": "Some Kerala nurseries may stock. Greens of Kerala region. Less common than integrifolia seedlings. Better suited cooler Indian hill stations (Kodaikanal, Munnar highlands). Lower cost option for experimentation.", "sort_order": 15}], "variety_count": 38}'::jsonb,
