UPDATE public.garden_import_queue SET payload = '{"species": "Myrrh", "species_slug": "myrrh", "varieties": [{"name": "Commiphora myrrha", "slug": "commiphora-myrrha", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Somalia, Ethiopia, Kenya, Yemen, Oman - Indigenous to Horn of Africa, cultivated for 3,000+ years", "traits": "Spiny deciduous shrub/small tree 4-5m tall. Papery silvery-whitish bark peeling in flakes. Green photosynthetic under-bark. Very thorny branches. Grey-green trifoliate leaves 6-44mm long. Compact, drought-adapted form", "flesh_fruit": "", "yield_notes": "Up to 4kg resin per tree annually when mature (3-5 years). Most valuable commercial myrrh species", "growing_notes": "", "availability": "Limited in Australia. Specialty online nurseries. May need to source as seeds from international suppliers", "sort_order": 0}, {"name": "Commiphora wightii", "slug": "commiphora-wightii", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Rajasthan and Gujarat, India - Indigenous to Indian subcontinent. Historically used in Ayurveda for 3,000+ years", "traits": "Spiny shrub 2-4m tall. Crooked, knotty branches ending in sharp spines. Papery bark peels in flakes. Trifoliate leaves with rhomboid ovate leaflets, serrate near apex. Pubescent young parts", "flesh_fruit": "", "yield_notes": "Moderate resin production. Critically endangered in wild due to over-harvesting. Commercial cultivation established", "growing_notes": "", "availability": "Available from Indian nurseries online (Nursery Nisarga, Lalit Enterprise, Paradise Found Nursery). Some Australian succulent specialists may stock", "sort_order": 1}, {"name": "Commiphora africana", "slug": "commiphora-africana", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Widespread sub-Saharan Africa - dry savannahs from West to East Africa", "traits": "Spiny deciduous shrub/small tree 3-5m (occasionally 10m). Short bole, dense rounded crown. Deciduous - bare for months in dry period. Peeling bark. Yellow-red flowers", "flesh_fruit": "", "yield_notes": "Moderate resin production when tapped", "growing_notes": "", "availability": "Very limited. Australian specialist - Herbalistics (herbalistics.com.au) occasionally stocks. Otherwise international seed suppliers", "sort_order": 2}, {"name": "Commiphora erythraea", "slug": "commiphora-erythraea", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Somalia, Kenya, Ethiopia, Southern Arabia - Red Sea coastal regions", "traits": "Small tree/shrub up to 5m. Greenish or brownish peeling bark. Trifoliate or 5-7 leaflets", "flesh_fruit": "", "yield_notes": "Good resin production. Valued in perfume industry", "growing_notes": "", "availability": "Extremely rare in cultivation. Would need to source from specialized collectors or grow from seed", "sort_order": 3}, {"name": "Commiphora gileadensis", "slug": "commiphora-gileadensis", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Saudi Arabia, Yemen, Oman, Sudan - Historically cultivated in ancient Israel (Ein Gedi, Jericho) from Biblical times", "traits": "Shrub/small tree 1-10m depending on microclimate. Rarely spiny. Peeling bark. Pleasant-smelling resin from broken twigs. Pinnate leaves with 3-5 oblong leaflets 5-40mm. Red flowers", "flesh_fruit": "", "yield_notes": "Moderate resin production. Ancient cultivation showed commercial viability", "growing_notes": "", "availability": "Extremely rare. Would need specialized sourcing or seed collection", "sort_order": 4}, {"name": "Commiphora holtziana", "slug": "commiphora-holtziana", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "East Africa - Somalia, Ethiopia, Kenya. Sometimes sold as sweet myrrh/opoponax", "traits": "Small deciduous tree to 6m. Similar growth habit to other Commiphora. Thorny branches", "flesh_fruit": "", "yield_notes": "Moderate resin production", "growing_notes": "", "availability": "Very rare in cultivation. Would need specialized sourcing", "sort_order": 5}, {"name": "Commiphora wightii", "slug": "commiphora-wightii", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Rajasthan, Gujarat, Maharashtra, Karnataka - Indigenous to Indian subcontinent. Kerala occurrence: RARE/occasional only", "traits": "Spiny shrub 2-4m. Thorny crooked branches. Papery peeling bark. Trifoliate serrate leaves. Gynodioecious flowers", "flesh_fruit": "", "yield_notes": "Plants yield 2-4kg resin over lifetime when tapped properly. Commercial cultivation established in dry regions of India", "growing_notes": "", "availability": "Available from Indian nurseries: Nursery Nisarga, Lalit Enterprise, Nature India Nursery, Plantsguru. Ships within India. Typically 12-18 inch plants in medium pots", "sort_order": 0}, {"name": "Commiphora berryi", "slug": "commiphora-berryi", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "South-West India - Grown as hedge plant in southwestern India including Kerala region. One of only 3 Commiphora species found in India", "traits": "Small tree/shrub. Used traditionally as hedging plant. More adapted to Indian conditions than Middle Eastern species", "flesh_fruit": "", "yield_notes": "Moderate resin production", "growing_notes": "", "availability": "Rare but occasionally available from south Indian botanical gardens or specialized collectors. May be grown in some Kerala temple/church compounds", "sort_order": 1}, {"name": "Commiphora stocksii", "slug": "commiphora-stocksii", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Western India - One of three Commiphora species found in India", "traits": "Small tree/shrub. Less documented than C. wightii and C. berryi", "flesh_fruit": "", "yield_notes": "Unknown - not commercially tapped", "growing_notes": "", "availability": "Extremely rare in cultivation. No known commercial sources", "sort_order": 2}, {"name": "Commiphora myrrha", "slug": "commiphora-myrrha", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Somalia, Ethiopia, Yemen, Oman - Biblical myrrh. NOT indigenous to India", "traits": "Spiny shrub/tree 4-5m. Papery silver-white bark. Very thorny. Trifoliate grey-green leaves", "flesh_fruit": "", "yield_notes": "Up to 4kg per tree annually when mature", "growing_notes": "", "availability": "Not available in India commercially. Would need international sourcing or seeds", "sort_order": 3}, {"name": "Commiphora caudata", "slug": "commiphora-caudata", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "India - Referenced in Indian botanical literature", "traits": "Small tree/shrub. Limited detailed documentation", "flesh_fruit": "", "yield_notes": "Not commercially harvested", "growing_notes": "", "availability": "Not available commercially", "sort_order": 4}], "variety_count": 11}'::jsonb,
